const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = 'payment_events';

async function processPayment(paymentData) {
  console.log('Processing payment:', paymentData);
  
  const { userId, amount, currency, action, accountId, recipientId } = paymentData;
  
  if (action === 'transfer') {
    console.log(`Transferring ${amount} ${currency} from user ${userId} to ${recipientId}`);
    // Execute transfer logic
    await executeTransfer(userId, recipientId, amount, currency);
  } else if (action === 'withdraw') {
    console.log(`Withdrawing ${amount} ${currency} from user ${userId} to account ${accountId}`);
    // Execute withdrawal logic
    await executeWithdrawal(userId, accountId, amount, currency);
  } else if (action === 'refund') {
    console.log(`Refunding ${amount} ${currency} to user ${userId}`);
    // Execute refund logic
    await executeRefund(userId, amount, currency);
  } else if (action === 'credit') {
    console.log(`Crediting ${amount} ${currency} to user ${userId}`);
    // Execute credit logic
    await executeCredit(userId, amount, currency);
  }
  
  console.log('Payment processed successfully');
}

async function executeTransfer(fromUserId, toUserId, amount, currency) {
  // Simulated database operations
  console.log(`DB: Deducting ${amount} ${currency} from user ${fromUserId}`);
  console.log(`DB: Adding ${amount} ${currency} to user ${toUserId}`);
  console.log('Transfer completed');
}

async function executeWithdrawal(userId, accountId, amount, currency) {
  // Simulated withdrawal
  console.log(`DB: Deducting ${amount} ${currency} from user ${userId}`);
  console.log(`External API: Initiating withdrawal to account ${accountId}`);
  console.log('Withdrawal completed');
}

async function executeRefund(userId, amount, currency) {
  // Simulated refund
  console.log(`DB: Adding ${amount} ${currency} to user ${userId}`);
  console.log('Refund completed');
}

async function executeCredit(userId, amount, currency) {
  // Simulated credit
  console.log(`DB: Adding ${amount} ${currency} to user ${userId}`);
  console.log('Credit completed');
}

async function startConsumer() {
  try {
    const connection = await amqp.connect(RABBITMQ_URL);
    const channel = await connection.createChannel();
    
    await channel.assertQueue(QUEUE_NAME, { durable: true });
    
    console.log(`Waiting for messages in queue: ${QUEUE_NAME}`);
    
    channel.consume(QUEUE_NAME, async (msg) => {
      if (msg !== null) {
        try {
          const messageContent = msg.content.toString();
          console.log('Received message:', messageContent);
          
          const paymentData = JSON.parse(messageContent);
          
          await processPayment(paymentData);
          
          channel.ack(msg);
        } catch (error) {
          console.error('Error processing message:', error);
          channel.ack(msg);
        }
      }
    });
    
    process.on('SIGINT', async () => {
      console.log('Closing connection...');
      await channel.close();
      await connection.close();
      process.exit(0);
    });
    
  } catch (error) {
    console.error('Failed to start consumer:', error);
    process.exit(1);
  }
}

startConsumer();